	SuspicionPeriods int
	// IndirectCheckStep increases IndirectChecks at each fanout scaling step.
	IndirectCheckStep int
	// IndirectCheckLevelInterval controls how often log2 levels increase fanout.
	IndirectCheckLevelInterval int
	// MaxIndirectChecks caps scaled indirect fanout. Values <= 0 mean no cap.
	MaxIndirectChecks int
}

