	return ScaledConfig{
		Base:                       DefaultSWIMConfig(),
		PeriodStep:                 250 * time.Millisecond,
		ProbeTimeoutRatio:          2,
		SuspicionPeriods:           5,
		IndirectCheckStep:          1,
		IndirectCheckLevelInterval: 2,
		MaxIndirectChecks:          10,
	}
