	base := nonnegativeDuration(c.Base.ProbeInterval)
	step := nonnegativeDuration(c.PeriodStep)
	level := scalingLevel(clusterSize)
	return saturatingAdd(base, saturatingMul(step, level))
}

// IndirectChecks returns the scaled indirect-probe fanout for the cluster size.
func (c ScaledConfig) IndirectChecks(clusterSize int) int {
	checks := c.Base.IndirectChecks
	if checks < 0 {
		checks = 0
	}

	step := c.IndirectCheckStep
	if step < 0 {
		step = 0
	}

	interval := c.IndirectCheckLevelInterval
	if interval <= 0 {
		interval = 1
	}

