    11	// ScaledConfig derives SWIM timing and fanout parameters from cluster size.
    12	//
    13	// Scaling is based on ceil(log2(clusterSize)) so that size 1 uses the base
    14	// values, powers of two advance one level at a time, and all results are
    15	// deterministic and monotonic for increasing cluster sizes.
    16	type ScaledConfig struct {
    17		// Base is the unscaled configuration used for a one-node cluster.
    18		Base SWIMConfig
    19		// PeriodStep is added to the protocol period for each log2 scaling level.
    20		PeriodStep time.Duration
    21		// ProbeTimeoutRatio derives ProbeTimeout from the scaled protocol period.
    22		ProbeTimeoutRatio int
    23		// SuspicionPeriods derives SuspicionTimeout from the scaled protocol period.
    24		SuspicionPeriods int
    25		// IndirectCheckStep increases IndirectChecks at each fanout scaling step.
    26		IndirectCheckStep int
    27		// IndirectCheckLevelInterval controls how often log2 levels increase fanout.
    28		IndirectCheckLevelInterval int
    29		// MaxIndirectChecks caps scaled indirect fanout. Values <= 0 mean no cap.
    30		MaxIndirectChecks int
    31	}
    32	
    33	// DefaultScaling returns stable log2-based scaling defaults for SWIM.
    34	func DefaultScaling() ScaledConfig {
    35		return ScaledConfig{
    36			Base:                       DefaultSWIMConfig(),
    37			PeriodStep:                 250 * time.Millisecond,
    38			ProbeTimeoutRatio:          2,
    39			SuspicionPeriods:           5,
    40			IndirectCheckStep:          1,
    41			IndirectCheckLevelInterval: 2,
    42			MaxIndirectChecks:          10,
    43		}
    44	}
    45	
    46	// SWIMConfig returns a SWIMConfig scaled for the supplied cluster size.
    47	func (c ScaledConfig) SWIMConfig(clusterSize int) SWIMConfig {
    48		period := c.ProtocolPeriod(clusterSize)
    49		return SWIMConfig{
    50			ProbeInterval:    period,
    51			ProbeTimeout:     c.probeTimeout(period),
    52			IndirectChecks:   c.IndirectChecks(clusterSize),
    53			SuspicionTimeout: c.suspicionTimeout(period),
    54		}
    55	}
    56	
    57	// ProtocolPeriod returns the scaled protocol period for the cluster size.
    58	func (c ScaledConfig) ProtocolPeriod(clusterSize int) time.Duration {
    59		base := nonnegativeDuration(c.Base.ProbeInterval)
    60		step := nonnegativeDuration(c.PeriodStep)
    61		level := scalingLevel(clusterSize)
    62		return saturatingAdd(base, saturatingMul(step, level))
    63	}
    64	
    65	// IndirectChecks returns the scaled indirect-probe fanout for the cluster size.
    66	func (c ScaledConfig) IndirectChecks(clusterSize int) int {
    67		checks := c.Base.IndirectChecks
    68		if checks < 0 {
    69			checks = 0
    70		}
    71	
    72		step := c.IndirectCheckStep
    73		if step < 0 {
    74			step = 0
    75		}
    76	
    77		interval := c.IndirectCheckLevelInterval
    78		if interval <= 0 {
    79			interval = 1
    80		}
    81	
    82		checks += (scalingLevel(clusterSize) / interval) * step
    83		if c.MaxIndirectChecks > 0 && checks > c.MaxIndirectChecks {
    84			return c.MaxIndirectChecks
    85		}
    86		return checks
    87	}
