    89	func (c ScaledConfig) probeTimeout(period time.Duration) time.Duration {
    90		base := nonnegativeDuration(c.Base.ProbeTimeout)
    91		ratio := c.ProbeTimeoutRatio
    92		if ratio <= 0 {
    93			ratio = 1
    94		}
    95	
    96		timeout := period / time.Duration(ratio)
    97		if timeout < base {
    98			timeout = base
    99		}
   100		if period > 0 && timeout > period {
   101			return period
   102		}
   103		return timeout
   104	}
