   106	func (c ScaledConfig) suspicionTimeout(period time.Duration) time.Duration {
   107		base := nonnegativeDuration(c.Base.SuspicionTimeout)
   108		if c.SuspicionPeriods <= 0 {
   109			return base
   110		}
   111	
   112		timeout := saturatingMul(period, c.SuspicionPeriods)
   113		if timeout < base {
   114			return base
