   126	func nonnegativeDuration(d time.Duration) time.Duration {
   127		if d < 0 {
   128			return 0
   129		}
   130		return d
   131	}
   132	
   133	func saturatingAdd(a, b time.Duration) time.Duration {
   134		if b > 0 && a > maxDuration-b {
   135			return maxDuration
   136		}
   137		return a + b
   138	}
   139	
   140	func saturatingMul(d time.Duration, n int) time.Duration {
   141		if d <= 0 || n <= 0 {
   142			return 0
   143		}
   144		factor := time.Duration(n)
   145		if d > maxDuration/factor {
   146			return maxDuration
   147		}
   148		return d * factor
   149	}
