   151	// ClusterSizeEstimator tracks unique observed node IDs for scaling decisions.
   152	//
   153	// The zero value is ready to use. Repeated observations of the same node do not
   154	// increase the estimate.
   155	type ClusterSizeEstimator struct {
   156		mu    sync.RWMutex
   157		nodes map[string]struct{}
   158	}
   159	
   160	// ObserveNode records a node ID and returns the current size estimate.
   161	func (e *ClusterSizeEstimator) ObserveNode(id string) int {
   162		if id == "" {
   163			return e.Estimate()
   164		}
   165	
   166		e.mu.Lock()
   167		defer e.mu.Unlock()
   168		if e.nodes == nil {
   169			e.nodes = make(map[string]struct{})
   170		}
   171		e.nodes[id] = struct{}{}
   172		return len(e.nodes)
   173	}
   174	
   175	// ObserveNodes records node IDs and returns the current size estimate.
   176	func (e *ClusterSizeEstimator) ObserveNodes(ids ...string) int {
   177		e.mu.Lock()
   178		defer e.mu.Unlock()
   179		if e.nodes == nil {
   180			e.nodes = make(map[string]struct{})
   181		}
   182		for _, id := range ids {
   183			if id == "" {
   184				continue
   185			}
   186			e.nodes[id] = struct{}{}
   187		}
   188		return len(e.nodes)
   189	}
   190	
   191	// Estimate returns the current unique-node count.
   192	func (e *ClusterSizeEstimator) Estimate() int {
   193		e.mu.RLock()
   194		defer e.mu.RUnlock()
   195		return len(e.nodes)
   196	}
   197	
   198	// Reset clears all observations.
   199	func (e *ClusterSizeEstimator) Reset() {
   200		e.mu.Lock()
   201		defer e.mu.Unlock()
   202		e.nodes = nil
   203	}

